const now = new Date();
const cutoff = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const allItems = $input.all().map((entry) => entry.json || {});
const uniqueByUrl = new Map();

const hostMap = [
  { match: 'yozm.wishket.com', source: 'YozmIT', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'techblog.woowahan.com', source: 'WoowahanTech', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'tech.kakao.com', source: 'KakaoTech', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'toss.tech', source: 'TossTech', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'd2.naver.com', source: 'NaverD2', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'medium.com', source: 'Danggeun(Alt:Medium)', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'tech.inflab.com', source: 'InflabTech', locale: 'ko', category: 'KR_IT_BLOG' },
  { match: 'tldr.tech', source: 'TLDR', locale: 'global', category: 'GLOBAL_AI' },
  { match: 'openai.com', source: 'OpenAI', locale: 'global', category: 'GLOBAL_AI' },
  { match: 'deepmind.google', source: 'GoogleDeepMind', locale: 'global', category: 'GLOBAL_AI' },
  { match: 'huggingface.co', source: 'HuggingFace', locale: 'global', category: 'GLOBAL_AI' },
  { match: 'dev.to', source: 'Dev.to', locale: 'global', category: 'GLOBAL_DEV_COMMUNITY' },
  { match: 'lobste.rs', source: 'Lobsters', locale: 'global', category: 'GLOBAL_DEV_COMMUNITY' },
];

function parsePublished(item) {
  const raw = item.isoDate || item.pubDate || item.published || item.date || '';
  const dt = raw ? new Date(raw) : null;
  if (!dt || Number.isNaN(dt.getTime())) return null;
  return dt;
}

function normalizeHost(url) {
  try {
    return new URL(url).hostname.toLowerCase();
  } catch {
    return '';
  }
}

function inferMeta(item, link) {
  const explicitSource = String(item.source || '').trim();
  const explicitLocale = String(item.locale || '').trim();
  const explicitCategory = String(item.category || '').trim();

  if (explicitSource || explicitLocale || explicitCategory) {
    const locale = explicitLocale || 'ko';
    return {
      source: explicitSource || 'unknown',
      locale,
      category: explicitCategory || 'OTHER',
      needs_translation: locale !== 'ko',
    };
  }

  const candidates = [
    String(item.feedUrl || ''),
    String(item.feed_url || ''),
    String(item.link || ''),
    String(item.url || ''),
    String(link || ''),
  ].filter(Boolean);

  for (const candidate of candidates) {
    const host = normalizeHost(candidate);
    if (!host) continue;
    const found = hostMap.find((rule) => host.includes(rule.match));
    if (found) {
      return {
        source: found.source,
        locale: found.locale,
        category: found.category,
        needs_translation: found.locale !== 'ko',
      };
    }
  }

  return {
    source: String(item.feedTitle || item.feed || item.creator || 'unknown').trim(),
    locale: 'ko',
    category: 'OTHER',
    needs_translation: false,
  };
}

for (const item of allItems) {
  const link = String(item.link || item.url || '').trim();
  if (!link) continue;

  const publishedAt = parsePublished(item);
  if (!publishedAt || publishedAt < cutoff || publishedAt > now) continue;

  const meta = inferMeta(item, link);
  const normalized = {
    source: meta.source,
    locale: meta.locale,
    category: meta.category,
    needs_translation: meta.needs_translation,
    title: String(item.title || '').replace(/\s+/g, ' ').trim(),
    url: link,
    published_at: publishedAt.toISOString(),
    summary: String(item.contentSnippet || item.content || item.summary || item.description || '').replace(/\s+/g, ' ').trim().slice(0, 260),
  };

  if (!normalized.title) continue;
  if (!uniqueByUrl.has(link)) {
    uniqueByUrl.set(link, normalized);
  }
}

const articles = Array.from(uniqueByUrl.values())
  .sort((a, b) => new Date(b.published_at).getTime() - new Date(a.published_at).getTime())
  .slice(0, 60);

const sourceStats = {};
for (const article of articles) {
  const key = article.source || 'unknown';
  sourceStats[key] = (sourceStats[key] || 0) + 1;
}

const translationRequiredCount = articles.filter((x) => x.needs_translation).length;
const periodStart = cutoff.toISOString();
const periodEnd = now.toISOString();

const lines = [];
lines.push('=== Hermes Daily Trend Input ===');
lines.push(`period_start: ${periodStart}`);
lines.push(`period_end: ${periodEnd}`);
lines.push(`article_count: ${articles.length}`);
lines.push(`translation_required_count: ${translationRequiredCount}`);
lines.push(`source_stats: ${JSON.stringify(sourceStats)}`);
lines.push('');

if (articles.length === 0) {
  lines.push('지난 24시간 내 신규 RSS 항목이 없습니다.');
} else {
  for (const [idx, item] of articles.entries()) {
    lines.push(`${idx + 1}. [${item.category}][${item.locale}] [${item.source || 'unknown'}] ${item.title}`);
    lines.push(`   - published_at: ${item.published_at}`);
    lines.push(`   - url: ${item.url}`);
    if (item.needs_translation) lines.push('   - note: translation_required');
    if (item.summary) lines.push(`   - summary: ${item.summary}`);
    lines.push('');
  }
}

return [{
  json: {
    period_start: periodStart,
    period_end: periodEnd,
    digest_text: lines.join('\n').trim(),
    translation_required_count: translationRequiredCount,
    source_stats: sourceStats,
    articles,
  },
}];
